import{_ as r,o as e,c as n,a2 as a}from"./chunks/framework.pnUkSPAE.js";const d="/diagrams/gantt.svg",c=JSON.parse('{"title":"前言","description":"","frontmatter":{"title":"前言"},"headers":[],"relativePath":"guide/preface.md","filePath":"guide/preface.md"}'),o={name:"guide/preface.md"};function i(h,t,l,g,s,A){return e(),n("div",null,[...t[0]||(t[0]=[a('<h2 id="为什么这份路线很重要" tabindex="-1">为什么这份路线很重要 <a class="header-anchor" href="#为什么这份路线很重要" aria-label="Permalink to &quot;为什么这份路线很重要&quot;">​</a></h2><p>2025-2026 年是国内 AI Agent 岗位的爆发期。AI Agent 市场规模预计从 2023 年的 574 亿元增长至 2028 年的 3.3 万亿元，超过 59.6% 的岗位月薪超过 25K，头部大厂 AI Agent 开发专家年薪可达 70-100 万。</p><p>通过对字节跳动、阿里、腾讯、百度、美团、华为六大厂的 JD 调研，总结出大厂最看重的 <strong>7 项核心能力</strong>：</p><img src="'+d+'" alt="20周学习甘特图" style="max-width:100%;height:auto;"><table tabindex="0"><thead><tr><th>能力</th><th>权重</th><th>大厂 JD 出现频率</th></tr></thead><tbody><tr><td>Python + 工程化能力</td><td>★★★★★</td><td>几乎所有岗位必考</td></tr><tr><td>LLM 应用开发（Prompt/SFT/RAG）</td><td>★★★★★</td><td>95%+</td></tr><tr><td>Agent 系统设计与实现</td><td>★★★★★</td><td>90%+</td></tr><tr><td>国产模型生态适配</td><td>★★★★</td><td>80%（大厂偏好自家模型）</td></tr><tr><td>分布式部署与高可用</td><td>★★★★</td><td>70%（P7+必问）</td></tr><tr><td>评估体系与 AB 测试</td><td>★★★★</td><td>65%</td></tr><tr><td>数据飞轮（RLHF/在线学习）</td><td>★★★</td><td>50%（加分项）</td></tr></tbody></table><hr><h2 id="_20-周路线总览" tabindex="-1">20 周路线总览 <a class="header-anchor" href="#_20-周路线总览" aria-label="Permalink to &quot;20 周路线总览&quot;">​</a></h2><img src="'+d+'" alt="20周学习甘特图" style="max-width:100%;height:auto;"><table tabindex="0"><thead><tr><th>周次</th><th>阶段</th><th>时间</th></tr></thead><tbody><tr><td>1-2</td><td>第一阶段：AI 基础理论（含国产模型生态）</td><td>30-40h</td></tr><tr><td>3-4</td><td>第二阶段：Prompt Engineering 与 Function Calling</td><td>30-35h</td></tr><tr><td>5</td><td>第三阶段：工程基建</td><td>15-20h</td></tr><tr><td>6-7</td><td>第四阶段：RAG 深度攻坚</td><td>35-40h</td></tr><tr><td>8-10</td><td>第五阶段：Agent 架构与设计模式</td><td>40-50h</td></tr><tr><td>11-13</td><td>第六阶段：主流框架实战</td><td>35-40h</td></tr><tr><td>14</td><td>第七阶段：MCP 与 A2A 协议</td><td>15-20h</td></tr><tr><td>15</td><td>第八阶段：多模态 Agent</td><td>15-20h</td></tr><tr><td>16</td><td>第九阶段：模型部署与推理优化</td><td>20-25h</td></tr><tr><td>17</td><td>第十阶段：安全、测试与可观测性</td><td>15-20h</td></tr><tr><td>18-20</td><td>第十一阶段：项目实战与面试准备</td><td>50-60h</td></tr></tbody></table><p><strong>总学习时间预估：300-350 小时</strong>（每周 15-18 小时）</p><hr><h2 id="_2026-年技术趋势总结" tabindex="-1">2026 年技术趋势总结 <a class="header-anchor" href="#_2026-年技术趋势总结" aria-label="Permalink to &quot;2026 年技术趋势总结&quot;">​</a></h2><ol><li><strong>Agent 框架收敛：</strong> OpenAI Agents SDK + LangGraph 成为事实标准</li><li><strong>MCP 生态爆发：</strong> 工具标准化使 Agent 能力快速扩展</li><li><strong>多模态成为标配：</strong> GPT-4o 级别视觉/语音能力向开源普及</li><li><strong>推理成本持续下降：</strong> DeepSeek V3/R1 + 量化部署</li><li><strong>国产模型崛起：</strong> DeepSeek、Qwen 在中文场景已接近 GPT-4 水平</li><li><strong>Agentic RAG 成为主流：</strong> 从被动检索转向主动、多步、自适应</li><li><strong>安全重视度提升：</strong> OWASP LLM Top 10 成为大厂标配</li><li><strong>端侧 Agent 兴起：</strong> 手机/PC 本地运行的轻量 Agent</li><li><strong>数据飞轮闭环：</strong> 用户反馈 → 自动标注 → 模型优化</li><li><strong>Agent 评估标准化：</strong> LLM-as-Judge + AB 测试成为标准流程</li></ol><hr><h2 id="各阶段学习优先级与时间分配" tabindex="-1">各阶段学习优先级与时间分配 <a class="header-anchor" href="#各阶段学习优先级与时间分配" aria-label="Permalink to &quot;各阶段学习优先级与时间分配&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>时间</th><th>P0（必须）</th><th>P1（重要）</th><th>P2（加分）</th></tr></thead><tbody><tr><td>一：AI 基础</td><td>30-40h</td><td>Transformer、LLM 原理</td><td>国产模型生态</td><td>论文精读</td></tr><tr><td>二：Prompt+FC</td><td>30-35h</td><td>Prompt Engineering、Function Calling</td><td>LangGPT</td><td>高级提示技术</td></tr><tr><td>三：工程基建</td><td>15-20h</td><td>Python 异步、FastAPI、Pydantic</td><td>分布式基础</td><td>K8s 深入</td></tr><tr><td>四：RAG</td><td>35-40h</td><td>RAG 全流程、向量库</td><td>Reranking、混合检索</td><td>Agentic RAG</td></tr><tr><td>五：Agent 架构</td><td>40-50h</td><td>ReAct、多 Agent、记忆管理</td><td>评估体系、AB 测试</td><td>数据飞轮</td></tr><tr><td>六：框架实战</td><td>35-40h</td><td>LangGraph、OpenAI SDK</td><td>CrewAI、Dify</td><td>Coze</td></tr><tr><td>七：协议</td><td>15-20h</td><td>MCP 概念</td><td>A2A</td><td>自定义协议</td></tr><tr><td>八：多模态</td><td>15-20h</td><td>视觉理解</td><td>音频</td><td>实时语音</td></tr><tr><td>九：部署优化</td><td>20-25h</td><td>vLLM、量化</td><td>分布式部署</td><td>SGLang</td></tr><tr><td>十：安全测试</td><td>15-20h</td><td>Prompt 注入防御</td><td>可观测性</td><td>渗透测试</td></tr><tr><td>十一：实战面试</td><td>50-60h</td><td>项目实战、面试题</td><td>系统设计</td><td>手撕代码</td></tr></tbody></table><hr><h2 id="最终建议" tabindex="-1">最终建议 <a class="header-anchor" href="#最终建议" aria-label="Permalink to &quot;最终建议&quot;">​</a></h2><ol><li><strong>项目驱动学习</strong>：每阶段做一个能跑的小 Demo，理论学到够用就行</li><li><strong>关注国产生态</strong>：面试国内大厂，DeepSeek + Qwen 是加分项</li><li><strong>工程能力是关键</strong>：大厂不只看 AI 知识，更看工程落地能力</li><li><strong>准备系统设计</strong>：P7+ 必考系统设计题，建议重点准备</li><li><strong>保持学习</strong>：Agent 技术快速演进，持续关注最新动态比掌握任何特定技术更重要</li></ol><p><strong>[热门] 2026 年大厂 AI Agent 岗位薪资参考：</strong></p><ul><li>P6（高级工程师）：40-60 万/年</li><li>P7（技术专家）：60-100 万/年</li><li>P8（高级专家）：100-150 万/年</li><li>Seed/星火计划（研究岗）：80-200 万/年</li></ul>',21)])])}const P=r(o,[["render",i]]);export{c as __pageData,P as default};
